sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading) {

    if (isLoading) {
        return;
    }

    // Hide all fields initially

    var fields = [
        'access_level',
        'device_type',
        'device_name',
        'start_date',
        'end_date',
        'ip_address',
        'port_number',
        'website_url',
        'building',
        'floor',
        'desk_number',
        'issue_description'
    ];

    for (var i = 0; i < fields.length; i++) {
        g_form.setDisplay(fields[i], false);
    }

    // Show fields based on Request Type

    switch (newValue) {

        case 'VPN Access':

            g_form.setDisplay('access_level', true);
            g_form.setDisplay('device_type', true);
            g_form.setDisplay('device_name', true);
            g_form.setDisplay('start_date', true);
            g_form.setDisplay('end_date', true);

            break;


        case 'Firewall Change':

            g_form.setDisplay('ip_address', true);
            g_form.setDisplay('port_number', true);

            break;


        case 'WiFi Access':

            g_form.setDisplay('device_type', true);
            g_form.setDisplay('device_name', true);

            break;


        case 'Internet Access':

            g_form.setDisplay('website_url', true);

            break;


        case 'LAN Port Activation':

            g_form.setDisplay('building', true);
            g_form.setDisplay('floor', true);
            g_form.setDisplay('desk_number', true);
            g_form.setDisplay('port_number', true);

            break;


        case 'Network Troubleshooting':

            g_form.setDisplay('device_type', true);
            g_form.setDisplay('device_name', true);
            g_form.setDisplay('issue_description', true);

            break;
    }

}
